package com.flowmind.user.service;import com.flowmind.common.security.TokenUtil;import com.flowmind.user.dto.LoginRequest;import com.flowmind.user.entity.UserEntity;import com.flowmind.user.mapper.UserMapper;import org.springframework.stereotype.Service;import java.util.Map;@Service public class UserService{private final UserMapper mapper;public UserService(UserMapper mapper){this.mapper=mapper;}public Map<String,Object> login(LoginRequest req){UserEntity user=mapper.findByUsername(req.getUsername()).filter(u->u.getPassword().equals(req.getPassword())).orElseThrow(()->new IllegalArgumentException("???????"));return Map.of("token",TokenUtil.createMockToken(user.getUsername()),"user",Map.of("id",user.getId(),"username",user.getUsername(),"nickname",user.getNickname(),"role",user.getRole()));}public UserEntity register(LoginRequest req){return mapper.save(new UserEntity(null,req.getUsername(),req.getPassword(),req.getUsername(),"OPERATOR"));}public Map<String,Object> me(){return Map.of("id",1,"username","admin","nickname","FlowMind ???","role","ADMIN","workspace","?????????");}}
